// Extract and validate input metadata
const body = $input.first().json.body;  // ← 關鍵！加 .body

if (!body.log_id || !body.log_content) {
  throw new Error('Missing required fields: log_id, log_content');
}

return [{
  json: {
    log_id: body.log_id,
    tool_name: body.tool_name || 'OpenROAD',
    verilog_files: body.verilog_files || [],
    log_content: body.log_content,
    rtl_content: body.rtl_content || null,
    ingested_at: new Date().toISOString()
  }
}];

// EDA Log Hybrid Parser: Regex → Structured Chunks
const { log_id, tool_name, log_content } = $input.first().json;

const patterns = {
  ERROR:       /\[ERROR\]|ERROR:|FATAL:|CRITICAL:/i,
  WARNING:     /\[WARNING\]|WARNING:|CAUTION:/i,
  WNS:         /WNS\s*[:\-]?\s*(-?\d+\.?\d*)/i,
  TNS:         /TNS\s*[:\-]?\s*(-?\d+\.?\d*)/i,
  MULTIDRIVEN: /multi[-_]?driven\s+(net_[^\s(]+)/i,
  LATCH:       /latch\s*(inferred|unexpected)/i,
  VIOLATION:   /(violat\S+|fail)/i,
  FILE_LINE:   /(?:file|line)\s+(\w+\.v?)[ :](\d+)/i,
  NET:         /net\s+(\S+)/i,
  MODULE:      /module\s+(\w+)/i
};

function getPriorityScore(meta) {
  let score = 0;
  if (meta.severity === 'ERROR')   score += 1.0;
  else if (meta.severity === 'WARNING') score += 0.7;
  if (meta.has_timing_violation)   score += 0.8;
  if (meta.timing_tns < 0)         score += 0.3;
  if (meta.issue_type === 'MULTIDRIVEN')    score += 0.6;
  if (meta.issue_type === 'LATCH_INFERRED') score += 0.5;
  if (meta.file) score += 0.2;
  if (meta.net)  score += 0.1;
  return Math.min(score, 2.0);
}

const lines = log_content.split('\n');
const chunks = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();
  if (!line || line.length < 10) continue;

  const metadata = {
    log_id,
    tool: tool_name,
    line_num: i + 1,
    severity: 'INFO'
  };

  if (patterns.ERROR.test(line))   metadata.severity = 'ERROR';
  else if (patterns.WARNING.test(line)) metadata.severity = 'WARNING';

  const wnsM = line.match(patterns.WNS);
  if (wnsM) {
    metadata.timing_wns = parseFloat(wnsM[1]);
    metadata.has_timing_violation = metadata.timing_wns < 0;
  }
  const tnsM = line.match(patterns.TNS);
  if (tnsM) metadata.timing_tns = parseFloat(tnsM[1]);

  if (patterns.MULTIDRIVEN.test(line)) {
    const nm = line.match(patterns.MULTIDRIVEN);
    metadata.issue_type = 'MULTIDRIVEN';
    metadata.net = nm[1];
  } else if (patterns.LATCH.test(line)) {
    metadata.issue_type = 'LATCH_INFERRED';
  } else if (patterns.VIOLATION.test(line)) {
    metadata.issue_type = 'VIOLATION';
  }

  const flM = line.match(patterns.FILE_LINE);
  if (flM) { metadata.file = flM[1]; metadata.file_line = parseInt(flM[2]); }

  const netM = line.match(patterns.NET);
  if (netM) metadata.net = netM[1];

  const modM = line.match(patterns.MODULE);
  if (modM) metadata.module = modM[1];

  const priority = getPriorityScore(metadata);
  chunks.push({ text: line, metadata, priority });
}

const highPriority = chunks
  .filter(c => c.priority > 0.3)
  .sort((a, b) => b.priority - a.priority)
  .slice(0, Math.floor(chunks.length * 0.8));

return [{
  json: {
    log_id,
    tool_name,
    total_lines: lines.length,
    error_count:   chunks.filter(c => c.metadata.severity === 'ERROR').length,
    warning_count: chunks.filter(c => c.metadata.severity === 'WARNING').length,
    timing_violations: chunks.filter(c => c.metadata.has_timing_violation).length,
    chunks: highPriority
  }
}];

// Split chunks into individual items for batch upload
const { log_id, chunks } = $input.first().json;

return chunks.map(chunk => ({
  json: {
    log_id,
    file_path: `${log_id}_${chunk.metadata.severity}_L${chunk.metadata.line_num}.txt`,
    text: chunk.text,
    metadata: chunk.metadata
  }
}));
